using System.Collections; using UnityEngine; using NabyeolDabyeolDreamPuzzle.Stage; using NabyeolDabyeolDreamPuzzle.Collection;
namespace NabyeolDabyeolDreamPuzzle.Save { public class CharacterAutoUnlockBinder:MonoBehaviour { [SerializeField] GoalManager goalManager; [SerializeField] CollectionManager collectionManager; [SerializeField] bool unlockOnStageCleared=true; [SerializeField] float unlockDelaySeconds=.05f; bool done; void Awake(){ goalManager??=FindAnyObjectByType<GoalManager>(); collectionManager??=FindAnyObjectByType<CollectionManager>(); } void OnEnable(){ if(unlockOnStageCleared&&goalManager!=null) goalManager.OnStageCleared+=Handle; } void OnDisable(){ if(goalManager!=null) goalManager.OnStageCleared-=Handle; } public void ResetUnlockFlag()=>done=false; public int UnlockAvailableCharactersNow(){ if(collectionManager==null) return 0; return collectionManager.TryUnlockAllAvailableCharacters(); } void Handle(){ if(done) return; StartCoroutine(Run()); } IEnumerator Run(){ done=true; if(unlockDelaySeconds>0) yield return new WaitForSeconds(unlockDelaySeconds); UnlockAvailableCharactersNow(); } } }
